mapper.update:
update t_wms_outbound set
	custcode = #{custcode},
	custname = #{custname}
where iid = #{iid}

update T_SM_DELIVERYBACKSUB_IF set
	custcode = #{custcode}
where ifno = #{ifno}

update T_SM_DELIVERYBACKSUB set
	custcode = #{custcode}
where ifno = #{ifno}

choose.when:
SELECT * FROM ( SELECT Z.*, COUNT(*) OVER() AS totalCount, NVL(SUM(NVL(Z.QTY,0)) OVER(),0) AS totalQty, NVL(SUM(NVL(Z.ERPQTY,0)) OVER(),0) AS totalErpQty, ROW_NUMBER() OVER(
) AS RN2 FROM ( SELECT FACTORY , CAR , ITEMCODE , ITEMNAME , SPEC , SUM(QTY) AS QTY , MAX(IN_IF_X) AS NOQTY1 , MAX(OUT_IF_X) AS NOQTY2 , MAX(OUT_IF_WAIT) AS NOQTY3 , SUM(QTY) - MAX(NVL(IN_IF_X,0)) + MAX(NVL(OUT_IF_X,0)) + MAX(NVL(OUT_IF_WAIT,0)) + MAX(NVL(UNPACK_QTY,0)) AS ERPQTY FROM ( SELECT a.FACTORY , a.STORAGE , a.CAR , a.ITEMCODE , a.ITEMNAME , b.SPEC AS SPEC , a.YYYYMM , SUM(a.QTY) AS QTY , SUM(a.IN_IF_X) AS IN_IF_X , SUM(a.OUT_IF_X) AS OUT_IF_X , SUM(a.OUT_IF_WAIT) AS OUT_IF_WAIT , SUM(a.UNPACK_QTY) AS UNPACK_QTY FROM V_STOCKSUM a LEFT JOIN T_MI_ITEM b ON b.ITEMCODE = a.ITEMCODE WHERE 1 = 1
GROUP BY a.FACTORY , a.STORAGE , a.CAR , a.ITEMCODE , a.ITEMNAME , b.SPEC , a.YYYYMM ) GROUP BY FACTORY , CAR , ITEMCODE , ITEMNAME , SPEC ) Z ) WHERE RN2 BETWEEN #{offset} + 1 AND #{offset} + #{itemsPerPage} ORDER BY RN2

mapper.select:
SELECT NVL(R.FACTORY, L.FACTORY) AS FACTORY, NVL(R.STORAGE, L.STORAGE) AS STORAGE, NVL(R.ITEMCODE, L.ITEMCODE) AS ITEMCODE, NVL(R.BARCODE, L.BARCODE) AS BARCODE, R.LOCATION AS RLOCATION, L.LOCATION AS LLOCATION, CASE WHEN R.LOCATION = L.LOCATION THEN 'TRUE' ELSE 'FALSE' END AS DIFFLOCATION, NVL(R.QTY, 0) AS RQTY, NVL(L.QTY, 0) AS LQTY, NVL(R.QTY, 0) - NVL(L.QTY, 0) AS DIFFQTY FROM ( SELECT FACTORY, STORAGE, ITEMCODE, BARCODE, LOCATION, QTY FROM ( SELECT FACTORY, STORAGE, ITEMCODE, BARCODE, LOCATION, QTY, ROW_NUMBER() OVER( PARTITION BY FACTORY, STORAGE, ITEMCODE, BARCODE ORDER BY CASE WHEN SCANTYPE = 'LOCATION' THEN 0 ELSE 1 END, SDATE DESC, YMDHMS DESC ) AS RN FROM T_WMS_REALSTOCK WHERE USEYN = 'Y' AND SDATE = #{searchParams.startdate}
AND UPPER(ITEMCODE) LIKE '%' || #{searchParams.itemcode} || '%'
) WHERE RN = 1
AND FACTORY = #{searchParams.factory}
AND storage = #{searchParams.storage}
AND storage = 'MATERIAL'
) R FULL JOIN ( SELECT SDATE, BARCODE, QTY, LOGINID, ITEMCODE, LOCATION, FACTORY, STORAGE FROM T_WMS_LOCATION WHERE ( USEYN = 'Y' OR YMDHMS_D > REPLACE(#{searchParams.startdate}, '-', '') || '235959')
AND factory = #{searchParams.factory}
AND storage = #{searchParams.storage}
AND storage = 'MATERIAL'
AND SDATE <= #{searchParams.startdate}
AND UPPER(itemcode) LIKE '%' || #{searchParams.itemcode} || '%'
AND UPPER(rack) LIKE '%' || UPPER(#{searchParams.rack}) || '%'
) L ON R.FACTORY = L.FACTORY AND R.STORAGE = L.STORAGE AND R.ITEMCODE = L.ITEMCODE AND R.BARCODE = L.BARCODE ORDER BY DIFFLOCATION, DIFFQTY, LLOCATION

SELECT X.FACTORY, UPPER(X.STORAGE) AS STORAGE, X.CAR, X.ITEMCODE, X.ITEMNAME,
SUM(X.CNT) AS countqty, SUM(X.NOSCANALL) - SUM(X.NOSCAN) AS INOUT, SUM(X.NOSCAN) AS noscanqty, SUM(X.NOSCANALL) AS noscanALLqty, SUM(X.ZERO_QTY) AS zeroqty, SUM(X.CNT) + SUM(X.NOSCANALL) AS totalqty,
#{startdate} AS sdate FROM ( /* 1) REALSTOCK */ SELECT A.FACTORY, UPPER(A.STORAGE) AS STORAGE, C.SUBNAME_CH AS CAR, A.ITEMCODE, B.ITEMNAME, SUM(A.QTY) AS CNT, 0 AS NOSCAN, 0 AS ZERO_QTY, 0 AS NOSCANALL FROM ( SELECT DISTINCT FACTORY, STORAGE, ITEMCODE, BARCODE, QTY FROM T_WMS_REALSTOCK WHERE USEYN = 'Y'
) A LEFT JOIN T_MI_ITEM B ON A.ITEMCODE = B.ITEMCODE LEFT JOIN T_MI_TYPESUB C ON B.CARNO = C.SUBCODE AND C.TYPECODE = 'MI041' GROUP BY A.FACTORY, A.STORAGE, C.SUBNAME_CH, A.ITEMCODE, B.ITEMNAME
UNION ALL
/* 2) NOSCAN */ SELECT L.FACTORY, UPPER(L.STORAGE) AS STORAGE, C.SUBNAME_CH AS CAR, L.ITEMCODE, I.ITEMNAME, 0 AS CNT, TO_NUMBER(L.QTY) AS NOSCAN, 0 AS ZERO_QTY, 0 AS NOSCANALL FROM T_WMS_LOCATIONBACKUP L LEFT JOIN T_WMS_REALSTOCK R ON R.USEYN='Y' AND R.BARCODE=L.BARCODE AND R.SDATE=#{startdate} LEFT JOIN T_MI_ITEM I ON I.ITEMCODE=L.ITEMCODE LEFT JOIN T_MI_TYPESUB C ON I.CARNO=C.SUBCODE AND C.TYPECODE='MI041' WHERE 1=1 AND L.USEYN='Y'
AND R.LOCATION IS NULL AND NOT EXISTS ( SELECT 1 FROM T_WMS_LOCATION LL WHERE LL.IID=L.IID AND LL.USEYN='N' AND UPPER(NVL(LL.MEMO_D,' ')) IN ('ADJUSTMENT','LOADEXCEPTION-NOSCAN') ) AND NOT ( NVL((SELECT MAX(LL.USEYN) FROM T_WMS_LOCATION LL WHERE LL.BARCODE=L.BARCODE AND LL.USEYN='Y'),'N') = 'N' OR NVL((SELECT 'Y' FROM T_WMS_REALSTOCK RR WHERE RR.BARCODE=L.BARCODE AND RR.SDATE>=#{startdate} AND ROWNUM=1 ),'N') = 'Y' )
UNION ALL
/* 3) NOSCAN ALL */ SELECT L.FACTORY, UPPER(L.STORAGE) AS STORAGE, C.SUBNAME_CH AS CAR, L.ITEMCODE, I.ITEMNAME, 0 AS CNT, 0 AS NOSCAN, 0 AS ZERO_QTY, TO_NUMBER(L.QTY) AS NOSCANALL FROM T_WMS_LOCATIONBACKUP L LEFT JOIN T_WMS_REALSTOCK R ON R.USEYN='Y' AND R.BARCODE=L.BARCODE AND R.SDATE=#{startdate} LEFT JOIN T_MI_ITEM I ON I.ITEMCODE=L.ITEMCODE LEFT JOIN T_MI_TYPESUB C ON I.CARNO=C.SUBCODE AND C.TYPECODE='MI041' WHERE 1=1 AND L.USEYN='Y'
AND R.LOCATION IS NULL
UNION ALL /* 4) ZERO */ SELECT L.FACTORY, UPPER(L.STORAGE) AS STORAGE, C.SUBNAME_CH AS CAR, L.ITEMCODE, I.ITEMNAME, 0 AS CNT, 0 AS NOSCAN, 0 AS ZERO_QTY, 0 AS NOSCANALL FROM ( SELECT DISTINCT FACTORY, STORAGE, ITEMCODE FROM T_WMS_LOCATION WHERE UPPER(FACTORY) = UPPER(#{factory})
AND UPPER(STORAGE) = UPPER(#{storage})
AND UPPER(STORAGE) = UPPER('Material')
) L LEFT JOIN T_MI_ITEM I ON I.ITEMCODE=L.ITEMCODE LEFT JOIN T_MI_TYPESUB C ON I.CARNO=C.SUBCODE AND C.TYPECODE='MI041'
) X WHERE 1=1
GROUP BY X.FACTORY, UPPER(X.STORAGE), X.CAR, X.ITEMCODE, X.ITEMNAME ORDER BY X.ITEMCODE

SELECT FACTORY, CAR, ITEMCODE, ITEMNAME, SUM(CNT) AS countqty, SUM(NOSCANALL)- SUM(NOSCAN) AS INOUT, SUM(NOSCAN) AS noscanqty, SUM(NOSCANALL) AS noscanALLqty, SUM(ZERO_QTY) AS zeroqty, SUM(cnt) + SUM(NOSCANALL) AS totalqty, #{startdate} as sdate FROM ( ----------------------------------------------------------------- -- 1) 실재고 COUNT ----------------------------------------------------------------- SELECT A.FACTORY, C.SUBNAME_CH AS CAR, A.itemcode, B.ITEMNAME, SUM(A.qty) AS CNT, 0 AS NOSCAN, 0 AS ZERO_QTY, 0 AS NOSCANALL FROM ( SELECT DISTINCT factory, itemcode, barcode, qty FROM T_WMS_REALSTOCK WHERE useyn = 'Y'
) A LEFT JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041' GROUP BY A.factory, A.itemcode, B.ITEMNAME, C.SUBNAME_CH
UNION ALL ----------------------------------------------------------------- -- 2) 미스캔 NOSCAN ----------------------------------------------------------------- SELECT l.factory, c.subname_ch AS car, l.itemcode, i.itemname, 0 AS cnt, TO_NUMBER(l.qty) AS noscan, 0 AS zero_qty, 0 AS NOSCANALL FROM t_wms_locationbackup l LEFT JOIN t_wms_realstock r ON r.useyn = 'Y' AND r.barcode = l.barcode AND r.sdate = #{startdate} LEFT JOIN t_mi_item i ON i.itemcode = l.itemcode LEFT JOIN t_mi_typesub c ON i.carno = c.subcode AND c.typecode = 'MI041' WHERE 1=1 AND L.USEYN = 'Y'
AND r.location IS NULL ---------------------------------------------------------------- -- ✅ 1. ADJUST / LOADEXCEPTION-NOSCAN 조정 건 제외 ---------------------------------------------------------------- AND NOT EXISTS ( SELECT 1 FROM t_wms_location ll WHERE ll.iid = l.iid AND ll.useyn = 'N' AND UPPER(NVL(ll.memo_d, ' ')) IN ('ADJUSTMENT', 'LOADEXCEPTION-NOSCAN') )
---------------------------------------------------------------- -- ✅ 2. NOSCAN 제외 조건 -- (1) 현재 바코드가 더 이상 사용중이 아닌 경우(useynbarcode = 'N') -- (2) 해당 바코드가 이후 실재고에서 다시 스캔된 경우(barcodescan = 'Y') ---------------------------------------------------------------- AND NOT ( --useynbarcode = 'N' 인 경우 NVL((SELECT MAX(ll.useyn) FROM t_wms_location ll WHERE ll.barcode = l.barcode AND ll.useyn = 'Y' ), 'N') = 'N' OR --barcodescan = 'Y' 인 경우 (해당 날짜 이후에 실재고에 다시 스캔됨) NVL((SELECT 'Y' FROM t_wms_realstock rr WHERE rr.barcode = l.barcode AND rr.sdate >= #{startdate} AND ROWNUM = 1 ), 'N') = 'Y' )
UNION ALL ----------------------------------------------------------------- -- 2) NOSCAN ALL ----------------------------------------------------------------- SELECT l.factory, c.subname_ch AS car, l.itemcode, i.itemname, 0 AS cnt, 0 AS NOSCAN, 0 AS zero_qty, TO_NUMBER(l.qty) AS noscanALL FROM t_wms_locationbackup l LEFT JOIN t_wms_realstock r ON r.useyn = 'Y' AND r.barcode = l.barcode AND r.sdate = #{startdate} LEFT JOIN t_mi_item i ON i.itemcode = l.itemcode LEFT JOIN t_mi_typesub c ON i.carno = c.subcode AND c.typecode = 'MI041' WHERE 1=1 AND L.USEYN = 'Y'
AND r.location IS NULL
UNION ALL ----------------------------------------------------------------- -- 3) ZERO 재고 : LOCATION 에는 있지만 총 qty = 0 OR REALSTOCK에도 없음 -----------------------------------------------------------------
SELECT L.factory, C.SUBNAME_CH AS CAR, L.itemcode, I.itemname, 0 AS CNT, 0 AS NOSCAN, 0 AS ZERO_QTY, -- 단순 표시용 0 AS NOSCANALL FROM ( SELECT DISTINCT itemcode, factory FROM t_wms_location WHERE upper(factory) = #{factory}
AND UPPER(storage) = UPPER(#{storage})
) L LEFT JOIN t_mi_item I ON I.itemcode = L.itemcode LEFT JOIN t_mi_typesub c ON I.carno = c.subcode AND c.typecode = 'MI041'
) where 1=1
GROUP BY FACTORY, CAR, ITEMCODE, ITEMNAME ORDER BY ITEMCODE
